  ) |&gt; 
  rbind(
    light_glasses_processed1 |&gt; 
  rbind(light_glasses_processed1) |&gt;
  filter(!is.implicit) |&gt;
  distinct(site, Id, Datetime, .keep_all = TRUE) |&gt;
  group_by(site, Id, nonwear = wear == "off" & sleep != "sleepprep") |&gt;
